// src/api/axiosConfig.js
import axios from 'axios';

// Use environment variable for the API base URL
// For development: REACT_APP_API_URL=http://localhost:3000/api
// For production: Set this variable on your hosting platform
const API = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:3000/api',
});

// Add a request interceptor to include the authorization token
API.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Optional: Add a response interceptor for global error handling or logging
API.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error("API call failed:", error.response?.data || error.message);
    // You could also dispatch a global toast or handle specific status codes here
    return Promise.reject(error);
  }
);

export default API;
